import React, { useState, useEffect } from 'react';
import './App.css';
import HomePage from './component/HomePage';
import AddRoomPage from './component/AddRoomPage';
import Header from './component/Header';
import AddDecoPage from './component/AddDecoPage';
import EditRoom from './component/EditRoom';
import {BrowserRouter as Router, Routes , Route} from 'react-router-dom';
import MyRooms from './component/MyRooms';


function App() {
  const [rooms, setRooms] = useState([])
  const [currentRoom, setCurrentRoom] = useState("")
  const [room, setRoom] = useState({})

  let addRoom=(room)=>{
      let r=rooms
    r.push(room)
    setRooms(r)
  }

  let addNewDeco=(name,newDeco)=>{
    let r= rooms.map((i) => {
      let rL=[]
      if(i.name==name){
        let l=i.items
        l.push(newDeco)
        rL.push({ name: i.name, roomType: i.roomType, roomColor: i.color ,items:l })
      }
      else 
      rL.push({ name: i.name, roomType: i.roomType, roomColor: i.color ,items:i.items })
    })
    setRooms(r)
  }

  return (
      <div className="App">
        <Header />
      <Router>
        <Routes>
          <Route path={'/'} element={<HomePage/>} />
          <Route path={'/addroom'} element={<AddRoomPage addRoom={addRoom}/>} />
          <Route path={'/myrooms'} element={<MyRooms  rooms={rooms} />} /> 
          {rooms.map((item) => {
            return (
              <Route path={"/"+item.name} element={<EditRoom room={item}/>}/>)})}
              {rooms.map((item) => {
            return (<Route path={"/"+item.roomName+"/addItems"} element={<AddDecoPage name={item.name} addNewDeco={addNewDeco}/>}/>)})}
        </Routes>
      </Router>
    </div>)}
export default App;
